import React, { useState, useEffect } from 'react';
import './Header.css';

function Header() {
  const [scrollPosition, setScrollPosition] = useState(0);
  const sectionIds = ['home', 'about', 'skills', 'experience', 'portfolio', 'contact'];

  useEffect(() => {
    const handleScroll = () => {
      const totalHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scroll = (window.scrollY / totalHeight) * 100;
      setScrollPosition(scroll);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToSection = (sectionId) => {
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: 'smooth' });
    }
  };

  const renderCircles = () => {
    return sectionIds.map((id, index) => {
      const isFilled = scrollPosition >= (index / sectionIds.length) * 100;
      return (
        <div key={id} className={`circle ${isFilled ? 'filled' : ''}`}>
          <span className="line" />
        </div>
      );
    });
  };

  return (
    <header>
      <div className="nav-container">
        <nav className="nav-menu">
          <ul>
            {sectionIds.map((sectionId) => (
              <li key={sectionId} onClick={() => scrollToSection(sectionId)}>
                {sectionId.charAt(0).toUpperCase() + sectionId.slice(1)}
              </li>
            ))}
          </ul>
        </nav>
        <div className="progress-bar">{renderCircles()}</div>
      </div>
    </header>
  );
}

export default Header;
